"import urllib.request
import json

def search_wikipedia(query):
    search_url = "https://en.wikipedia.org/w/api.php"
    headers = {
        "User-Agent": "Mozilla/5.0"
    }
    params = f"?action=query&list=search&srsearch={urllib.parse.quote(query)}&format=json"
    try:
        req = urllib.request.Request(search_url + params, headers=headers)
        with urllib.request.urlopen(req, timeout=10) as r:
            data = json.loads(r.read().decode('utf-8'))
            return data.get("query", {}).get("search", [])
    except Exception as e:
        print(f"Failed search for {query}: {e}")
    return []

for q in ["Jeh Vincent Johnson architect", "Jeh Vincent Johnson", "Robert Kennard architect", "Robert Kennard"]:
    res = search_wikipedia(q)
    print(f"\nQuery: {q}")
    for idx, r in enumerate(res[:3]):
        print(f"  {idx+1}: Title='{r['title']}', Snippet='{r['snippet']}'")
"

