"import os
import shutil
import time

project_root = r"c:\Users\thoma\Dropbox\My Documents\Websites\NIA Website"
done_dir = os.path.join(project_root, "architects", "_Done")
notdone_dir = os.path.join(project_root, "architects", "_NotDone")

wrong_architects = [
    ("Jeh Vincent Johnson", "jeh-vincent-johnson"),
    ("Robert Kennard", "robert-kennard")
]

for name, slug in wrong_architects:
    src_path = os.path.join(done_dir, name)
    dst_path = os.path.join(notdone_dir, name)

    if os.path.exists(src_path):
        print(f"Processing wrong run directory for {name}...")

        # Delete generated markdown files
        draft_file = os.path.join(src_path, f"NIA-pioneers-{slug}-draft-2026-06-10.md")
        import_file = os.path.join(src_path, f"NIA-pioneers-{slug}.md")
        log_file = os.path.join(src_path, f"2026-06-10-{slug}.log")

        for f_path in [draft_file, import_file, log_file]:
            if os.path.exists(f_path):
                try:
                    os.remove(f_path)
                    print(f"  Deleted generated file: {os.path.basename(f_path)}")
                except Exception as e:
                    print(f"  Warning: Could not delete {os.path.basename(f_path)}: {e}")

        # Delete files inside buildings folder
        bldg_dir = os.path.join(src_path, "buildings")
        if os.path.exists(bldg_dir):
            for f in os.listdir(bldg_dir):
                f_path = os.path.join(bldg_dir, f)
                try:
                    os.remove(f_path)
                    print(f"  Deleted building image: {f}")
                except Exception as e:
                    print(f"  Warning: Could not delete building image {f}: {e}")
            try:
                os.rmdir(bldg_dir)
