import json

def main():
    try:
        # Run PowerShell command to get all scheduled tasks as JSON
        ps_cmd = "Get-ScheduledTask | Select-Object TaskName, TaskPath | ConvertTo-Json -Depth 2"
        out = subprocess.check_output(["powershell", "-Command", ps_cmd]).decode("utf-8", errors="ignore")
        tasks = json.loads(out)

        found = False
        print("Scheduled Tasks containing 'nia' or 'agent' (case-insensitive):")
        for t in tasks:
            name = t.get("TaskName", "")
            path = t.get("TaskPath", "")
            if "nia" in name.lower() or "agent" in name.lower():
                print(f"Path: {path} | Name: {name}")
                found = True
        if not found:
            print("No matching scheduled tasks found.")

    except Exception as e:
        print(f"Error checking tasks: {e}")

if __name__ == "__main__":
